print("Expanding state schemes batch 1 ...")
sd = read("schemes_data.py")
count = 0

for slug, new_data in E.items():
    slug_marker = '"slug": "' + slug + '"'
    alt_marker = '"slug":"' + slug + '"'
    pos = sd.find(slug_marker)
    if pos < 0:
        pos = sd.find(alt_marker)
    if pos < 0:
        print("  Skip: " + slug)
        continue
    hi_start = sd.find('"hi":', pos)
    if hi_start < 0 or hi_start > pos + 2000:
        hi_start = sd.find('"hi" :', pos)
    if hi_start < 0 or hi_start > pos + 2000:
        print("  Skip: " + slug + " hi not found")
        continue
    hi_brace = sd.find('{', hi_start)
    depth = 0
    hi_end = hi_brace
    for i in range(hi_brace, len(sd)):
        if sd[i] == '{':
            depth += 1
        elif sd[i] == '}':
            depth -= 1
            if depth == 0:
                hi_end = i + 1
                break
    try:
        current_hi = ast.literal_eval(sd[hi_brace:hi_end])
    except:
        print("  Skip: " + slug + " parse error")
        continue
    for key in new_data:
        current_hi[key] = new_data[key]
    new_hi_str = "{\n"
    for k, v in current_hi.items():
        new_hi_str += '   "' + k + '": ' + repr(v) + ',\n'
    new_hi_str += "  }"
    sd = sd[:hi_brace] + new_hi_str + sd[hi_end:]
    count += 1
    print("  Done: " + slug)

write("schemes_data.py", sd)
print("\nExpanded " + str(count) + " schemes")

print("\nRebuilding ...")
os.chdir(REPO)
r = os.system(sys.executable + " generate.py")
if r == 0:
    print("OK!")
else:
    print("ERROR")
    sys.exit(1)

